// Custom exception class
class TestExecutionException extends Exception {
    public TestExecutionException(String message) {
        super(message);
    }

    public TestExecutionException(String message, Throwable cause) {
        super(message, cause);
    }
}

public class TestExecutor {
    private int passedTests = 0;
    private int failedTests = 0;
    private int skippedTests = 0;

    public TestExecutor() {
        this.passedTests = 0;
        this.failedTests = 0;
        this.skippedTests = 0;
    }

    public void executeTest(String testName, boolean shouldFail) throws TestExecutionException {
        System.out.println("Executing: " + testName);

        if (shouldFail) {
            throw new TestExecutionException("Test failed: " + testName);
        }

        System.out.println("Test passed: " + testName);
    }

    public void executeTestSuite(String[] testNames, boolean[] shouldFail) {
        if (testNames == null || shouldFail == null || testNames.length != shouldFail.length) {
            System.out.println("Invalid test suite configuration");
            return;
        }

        for (int i = 0; i < testNames.length; i++) {
            try {
                executeTest(testNames[i], shouldFail[i]);
                passedTests++;
            } catch (TestExecutionException e) {
                System.out.println("Caught exception: " + e.getMessage());
                failedTests++;
            } finally {
                System.out.println("Cleanup for: " + testNames[i]);
            }
        }
    }

    public String getExecutionSummary() {
        int total = passedTests + failedTests + skippedTests;
        double passRate = total > 0 ? (passedTests * 100.0) / total : 0.0;
        return String.format("Total: %d, Passed: %d, Failed: %d, Skipped: %d, Pass Rate: %.2f%%",
                           total, passedTests, failedTests, skippedTests, passRate);
    }

    public int getPassedTests() {
        return passedTests;
    }

    public int getFailedTests() {
        return failedTests;
    }

    public int getSkippedTests() {
        return skippedTests;
    }

    public static void main(String[] args) {
        TestExecutor executor = new TestExecutor();
        String[] tests = {"LoginTest", "LogoutTest", "SearchTest", "CheckoutTest"};
        boolean[] failures = {false, true, false, true};

        executor.executeTestSuite(tests, failures);
        System.out.println("\n" + executor.getExecutionSummary());
    }
}
